              title={
                <div style={{ display: 'flex', alignItems: 'center' }}>
                  <TeamOutlined style={{ marginRight: '8px', color: '#1890ff' }} />
                  Student Activity Monitoring
                  <Tag color="blue" style={{ marginLeft: '12px' }}>
                    {students.length} Total Students
                  </Tag>
                </div>
              }
              extra={
                <Space>
                  <Select
                    defaultValue="all"
                    style={{ width: 120 }}
                    onChange={(value) => setRoleFilter(value)}
                  >
                    <Option value="all">All Students</Option>
                    <Option value="active">Active Only</Option>
                    <Option value="inactive">Inactive Only</Option>
                    <Option value="pending">Pending Approval</Option>
                  </Select>
                  <Button icon={<ReloadOutlined />} onClick={fetchStudents}>
                    Refresh
                  </Button>
                </Space>
              }
              style={{ borderRadius: '12px' }}
            >
              <Table
                columns={[
                  {
                    title: 'Student Info',
                    key: 'studentInfo',
                    render: (_, record) => (
                      <div style={{ display: 'flex', alignItems: 'center' }}>
                        <Avatar 
                          style={{ 
                            backgroundColor: record.isApproved ? '#52c41a' : '#faad14',
                            marginRight: 12 
                          }}
                        >
                          {record.firstName?.[0]}{record.lastName?.[0]}
                        </Avatar>
                        <div>
                          <Text strong style={{ color: '#1890ff' }}>
                            {record.firstName} {record.lastName}
                          </Text>
                          <br />
                          <Text type="secondary" style={{ fontSize: '12px' }}>
                            {record.email}
                          </Text>
                        </div>
                      </div>
                    ),
                    width: 250,
                  },
                  {
                    title: 'Status',
                    key: 'status',
                    render: (_, record) => (
                      <div>
                        <Tag color={record.isApproved ? 'green' : 'orange'}>
                          {record.isApproved ? 'Active' : 'Pending'}
                        </Tag>
                        <br />
                        <Text type="secondary" style={{ fontSize: '12px' }}>
                          Role: {record.role}
                        </Text>
                      </div>
                    ),
                    filters: [
                      { text: 'Active', value: true },
                      { text: 'Pending', value: false }
                    ],
                    onFilter: (value, record) => record.isApproved === value,
                    width: 120,
                  },
                  {
                    title: 'Enrollment Details',
                    key: 'enrollment',
                    render: () => (
                      <div>
                        <Text strong>{Math.floor(Math.random() * 5) + 1}</Text>
                        <Text type="secondary"> courses enrolled</Text>
                        <br />
                        <Progress 
                          percent={Math.floor(Math.random() * 100)}
                          size="small"
                          strokeColor={
                            Math.random() > 0.3 ? '#52c41a' : 
                            Math.random() > 0.1 ? '#faad14' : '#f5222d'
                          }
                        />
                        <Text type="secondary" style={{ fontSize: '11px' }}>
                          Overall Progress
                        </Text>
                      </div>
                    ),
                    width: 160,
                  },
                  {
                    title: 'Last Activity',
                    key: 'lastActivity',
                    render: () => {
                      const daysAgo = Math.floor(Math.random() * 30);
                      const isRecent = daysAgo < 7;
                      return (
                        <div>
                          <Tag color={isRecent ? 'green' : daysAgo < 14 ? 'orange' : 'red'}>
                            {daysAgo === 0 ? 'Today' : `${daysAgo} days ago`}
                          </Tag>
                          <br />
                          <Text type="secondary" style={{ fontSize: '11px' }}>
                            {isRecent ? 'Recently Active' : daysAgo < 14 ? 'Moderately Active' : 'Inactive'}
                          </Text>
                        </div>
                      );
                    },
                    sorter: (a, b) => Math.random() - 0.5,
                    width: 130,
                  },
                  {
                    title: 'Performance',
                    key: 'performance',
                    render: () => {
                      const score = Math.floor(Math.random() * 40) + 60;
                      const submissions = Math.floor(Math.random() * 20) + 5;
                      return (
                        <div>
                          <div style={{ display: 'flex', alignItems: 'center' }}>
                            <Text strong style={{ 
                              color: score >= 85 ? '#52c41a' : score >= 70 ? '#faad14' : '#f5222d' 
                            }}>
                              {score}%
                            </Text>
                            <Text type="secondary" style={{ marginLeft: 8, fontSize: '11px' }}>
                              avg score
                            </Text>
                          </div>
                          <Text type="secondary" style={{ fontSize: '11px' }}>
                            {submissions} submissions
                          </Text>
                        </div>
                      );
                    },
                    sorter: (a, b) => Math.random() - 0.5,
                    width: 120,
                  },
                  {
                    title: 'Actions',
                    key: 'actions',
                    render: (_, record) => (
                      <Space>
                        <Button
                          icon={<EyeOutlined />}
                          size="small"
                          type="link"
                          onClick={() => {
                            setSelectedUser(record);
                            setUserModalVisible(true);
                          }}
                        >
                          View
                        </Button>
                        <Button
                          icon={<MessageOutlined />}
                          size="small"
                          type="link"
                          onClick={() => {
                            setReplyType('student');
                            setReplyTarget(record);
                            setReplyModalVisible(true);
                          }}
                        >
                          Message
                        </Button>
                      </Space>
                    ),
                    width: 120,
                  }
                ]}
                dataSource={students.filter(student => {
                  if (roleFilter === 'active') return student.isApproved;
                  if (roleFilter === 'inactive') return !student.isApproved;
                  if (roleFilter === 'pending') return !student.isApproved;
                  return true;
                })}
                rowKey="_id"
                pagination={{
                  pageSize: 8,
                  showSizeChanger: true,
                  showQuickJumper: true,
                  showTotal: (total, range) => `${range[0]}-${range[1]} of ${total} students`
                }}
                scroll={{ x: 1200 }}
              />
            </Card>
          </Col>
        </Row>

        <Row gutter={[24, 24]} style={{ marginTop: '24px' }}>
          <Col xs={24}>
            <Card 
              title={
                <div style={{ display: 'flex', alignItems: 'center' }}>
                  <UserOutlined style={{ marginRight: '8px', color: '#52c41a' }} />
                  Teacher Activity Monitoring
                  <Tag color="green" style={{ marginLeft: '12px' }}>
                    {teachers.length || users.filter(u => u.role === 'teacher').length} Total Teachers
                  </Tag>
                </div>
              }
              extra={
                <Space>
                  <Select
                    defaultValue="all"
                    style={{ width: 120 }}
                  >
                    <Option value="all">All Teachers</Option>
                    <Option value="active">Active Only</Option>
                    <Option value="inactive">Inactive Only</Option>
                  </Select>
                  <Button icon={<ReloadOutlined />} onClick={fetchUsers}>
                    Refresh
                  </Button>
                </Space>
              }
              style={{ borderRadius: '12px' }}
            >
              <Table
                columns={[
                  {
                    title: 'Teacher Info',
                    key: 'teacherInfo',
                    render: (_, record) => (
                      <div style={{ display: 'flex', alignItems: 'center' }}>
                        <Avatar 
                          style={{ 
                            backgroundColor: record.isApproved ? '#52c41a' : '#faad14',
                            marginRight: 12 
                          }}
                        >
                          {record.firstName?.[0]}{record.lastName?.[0]}
                        </Avatar>
                        <div>
                          <Text strong style={{ color: '#52c41a' }}>
                            {record.firstName} {record.lastName}
                          </Text>
                          <br />
                          <Text type="secondary" style={{ fontSize: '12px' }}>
                            {record.email}
                          </Text>
                        </div>
                      </div>
                    ),
                    width: 250,
                  },
                  {
                    title: 'Status',
                    key: 'status',
                    render: (_, record) => (
                      <div>
                        <Tag color={record.isApproved ? 'green' : 'orange'}>
                          {record.isApproved ? 'Active' : 'Pending'}
                        </Tag>
                        <br />
                        <Tag color="blue" size="small">
                          {record.role}
                        </Tag>
                      </div>
                    ),
                    filters: [
                      { text: 'Active', value: true },
                      { text: 'Pending', value: false }
                    ],
                    onFilter: (value, record) => record.isApproved === value,
                    width: 120,
                  },
                  {
                    title: 'Teaching Load',
                    key: 'teachingLoad',
                    render: () => {
                      const assignedCourses = Math.floor(Math.random() * 6) + 1;
                      const activeStudents = Math.floor(Math.random() * 50) + 10;
                      return (
                        <div>
                          <Text strong>{assignedCourses}</Text>
                          <Text type="secondary"> courses</Text>
                          <br />
                          <Text strong>{activeStudents}</Text>
                          <Text type="secondary" style={{ fontSize: '11px' }}> active students</Text>
                          <br />
                          <Progress 
                            percent={Math.min((assignedCourses / 6) * 100, 100)}
                            size="small"
                            strokeColor={assignedCourses > 4 ? '#f5222d' : assignedCourses > 2 ? '#faad14' : '#52c41a'}
                          />
                        </div>
                      );
                    },
                    width: 150,
                  },
                  {
                    title: 'Last Activity',
                    key: 'lastActivity',
                    render: () => {
                      const hoursAgo = Math.floor(Math.random() * 72);
                      const isRecent = hoursAgo < 24;
                      return (
                        <div>
                          <Tag color={isRecent ? 'green' : hoursAgo < 48 ? 'orange' : 'red'}>
                            {hoursAgo < 1 ? 'Just now' : 
                             hoursAgo < 24 ? `${hoursAgo}h ago` : 
                             `${Math.floor(hoursAgo / 24)}d ago`}
                          </Tag>
                          <br />
                          <Text type="secondary" style={{ fontSize: '11px' }}>
                            {isRecent ? 'Online' : hoursAgo < 48 ? 'Recently Online' : 'Offline'}
                          </Text>
                        </div>
                      );
                    },
                    width: 130,
                  },
                  {
                    title: 'Performance Metrics',
                    key: 'performance',
                    render: () => {
                      const studentSatisfaction = Math.floor(Math.random() * 30) + 70;
                      const responseTime = Math.floor(Math.random() * 48) + 2;
                      return (
                        <div>
                          <div style={{ display: 'flex', alignItems: 'center' }}>
                            <Rate 
                              disabled 
                              defaultValue={Math.floor(studentSatisfaction / 20)} 
                              style={{ fontSize: 12 }}
                            />
                            <Text style={{ marginLeft: 4, fontSize: '11px', color: '#faad14' }}>
                              {(studentSatisfaction / 20).toFixed(1)}
                            </Text>
                          </div>
                          <Text type="secondary" style={{ fontSize: '11px' }}>
                            ~{responseTime}h response time
                          </Text>
                        </div>
                      );
                    },
                    width: 160,
                  },
                  {
                    title: 'Actions',
                    key: 'actions',
                    render: (_, record) => (
                      <Space>
                        <Button
                          icon={<EyeOutlined />}
                          size="small"
                          type="link"
                          onClick={() => {
                            setSelectedUser(record);
                            setUserModalVisible(true);
                          }}
                        >
                          View
                        </Button>
                        <Button
                          icon={<MessageOutlined />}
                          size="small"
                          type="link"
                          onClick={() => {
                            setReplyType('teacher');
                            setReplyTarget(record);
                            setReplyModalVisible(true);
                          }}
                        >
                          Message
                        </Button>
                      </Space>
                    ),
                    width: 120,
                  }
                ]}
                dataSource={users.filter(user => user.role === 'teacher' || user.role === 'admin')}
                rowKey="_id"
                pagination={{
                  pageSize: 8,
                  showSizeChanger: true,
                  showQuickJumper: true,
                  showTotal: (total, range) => `${range[0]}-${range[1]} of ${total} teachers`
                }}
                scroll={{ x: 1200 }}
              />
            </Card>
          </Col>
        </Row>

        {/* Quick Activity Summary */}
        <Row gutter={[24, 24]} style={{ marginTop: '24px' }}>
          <Col xs={24} sm={12} lg={8}>
            <Card 
              title="Active Users Summary"
              style={{ borderRadius: '12px' }}
            >
              <Statistic
                title="Currently Online"
                value={Math.floor(Math.random() * 20) + 5}
                prefix={<UserOutlined />}
                valueStyle={{ color: '#52c41a' }}
                suffix="users"
              />
              <div style={{ marginTop: 16 }}>
                <Text type="secondary">
                  <TeamOutlined style={{ marginRight: 4 }} />
                  {Math.floor(Math.random() * 15) + 3} students, {Math.floor(Math.random() * 5) + 2} teachers
                </Text>
              </div>
            </Card>
          </Col>
          
          <Col xs={24} sm={12} lg={8}>
            <Card 
              title="Activity This Week"
              style={{ borderRadius: '12px' }}
            >
              <Statistic
                title="Login Sessions"
                value={Math.floor(Math.random() * 200) + 150}
                prefix={<LoginOutlined />}
                valueStyle={{ color: '#1890ff' }}
              />
              <div style={{ marginTop: 16 }}>
                <Text type="secondary">
                  <ArrowUpOutlined style={{ color: '#52c41a', marginRight: 4 }} />
                  +{Math.floor(Math.random() * 20) + 5}% from last week
                </Text>
              </div>
            </Card>
          </Col>
          
          <Col xs={24} sm={12} lg={8}>
            <Card 
              title="Attention Required"
              style={{ borderRadius: '12px' }}
            >
              <Statistic
                title="Inactive Users"
                value={Math.floor(Math.random() * 10) + 2}
                prefix={<ExclamationCircleOutlined />}
                valueStyle={{ color: '#f5222d' }}
                suffix="users"
              />
              <div style={{ marginTop: 16 }}>
                <Text type="secondary">
                  <ClockCircleOutlined style={{ marginRight: 4 }} />
                  Not active for 14+ days
                </Text>
              </div>
            </Card>
          </Col>
        </Row>
      </div>
    );
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
      }}>
        <Spin size="large" tip="Loading Dashboard..." />
      </div>
    );
  }

  // Main content renderer with integrated dashboard components
  const renderContent = () => {
    switch(activeKey) {
      case 'overview':
        return renderOverview();
      case 'applications':
        return renderApplicationsManagement();
      case 'enrollments':
        return renderEnrollmentsManagement();
      case 'courses':
        return renderCourseManagement();
      case 'materials':
        return renderMaterialManagement();
      case 'quizzes':
        return renderQuizManagement();
      case 'homework':
        return renderHomeworkManagement();
      case 'listening':
        return renderListeningExercises();
      case 'students':
        return renderStudentProgress();
      case 'analytics':
        return renderAnalytics();
      case 'settings':
        return renderSettings();
      default:
        return renderOverview();
    }
  };

  return (
    <Layout style={{ minHeight: '100vh' }}>
      {/* Modern Sidebar */}
      <Sider 
        trigger={null} 
        collapsible 
        collapsed={collapsed}
        breakpoint="lg"
        onBreakpoint={(broken) => {
          setCollapsed(broken);
        }}
        width={260}
        className="modern-sidebar"
        style={{
          background: 'linear-gradient(180deg, #667eea 0%, #764ba2 50%, #f093fb 100%)',
          position: 'fixed',
          height: '100vh',
          left: 0,
          top: 0,
          bottom: 0,
          zIndex: 1000,
          boxShadow: '4px 0 30px rgba(102, 126, 234, 0.4)',
          overflow: 'auto'
        }}
      >
        {/* Logo Section */}
        <div className="sidebar-logo-section" style={{
          padding: '30px 20px',
          textAlign: 'center',
          borderBottom: '2px solid rgba(255, 255, 255, 0.2)',
          background: 'rgba(255, 255, 255, 0.1)'
        }}>
          <div className="logo-container">
            <div className="logo-icon-box" style={{
              width: 70,
              height: 70,
              margin: '0 auto',
              background: 'linear-gradient(135deg, #ff6b6b 0%, #ee5a52 100%)',
              borderRadius: 20,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: '0 10px 30px rgba(255, 107, 107, 0.4)',
              marginBottom: 15
            }}>
              <RocketOutlined style={{ fontSize: 35, color: '#fff' }} />
            </div>
            {!collapsed && (
              <div>
                <Title level={3} style={{ color: '#fff', margin: 0 }}>
                  Forum Academy
                </Title>
                <Badge 
                  count="ADMIN PORTAL" 
                  style={{ 
                    backgroundColor: '#52c41a',
                    color: '#fff',
                    marginTop: 8
                  }} 
                />
              </div>
            )}
          </div>
        </div>
        
        {/* Navigation Menu */}
        <Menu
          theme="dark"
          mode="inline"
          selectedKeys={[activeKey]}
          onClick={(e) => setActiveKey(e.key)}
          style={{ 
            background: 'transparent',
            borderRight: 0,
            padding: '20px 10px'
          }}
          items={menuItems.map(item => ({
            ...item,
            style: {
              margin: '8px 0',
              borderRadius: '12px'
            }
          }))}
        />
      </Sider>

      {/* Main Layout */}
      <Layout style={{ marginLeft: collapsed ? 80 : 260, transition: 'all 0.3s' }}>
        {/* Header */}
        <Header style={{ 
          padding: '0 24px', 
          background: '#fff',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          position: 'sticky',
          top: 0,
          zIndex: 999
        }}>
          <div style={{ display: 'flex', alignItems: 'center' }}>
            <Button
              type="text"
              icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
              onClick={() => setCollapsed(!collapsed)}
              style={{
                fontSize: '16px',
                width: 64,
                height: 64,
              }}
            />
            <Breadcrumb style={{ marginLeft: 16 }}>
              <Breadcrumb.Item>
                <HomeOutlined />
              </Breadcrumb.Item>
              <Breadcrumb.Item>Dashboard</Breadcrumb.Item>
              <Breadcrumb.Item>{menuItems.find(item => item.key === activeKey)?.label}</Breadcrumb.Item>
            </Breadcrumb>
          </div>
          
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            {/* Notifications */}
            <Badge count={5}>
              <Button
                type="text"
                icon={<BellOutlined />}
                style={{ fontSize: 18 }}
              />
            </Badge>
            
            {/* User Profile Dropdown */}
            <Dropdown
              menu={{
                items: [
                  {
                    key: 'profile',
                    icon: <UserOutlined />,
                    label: 'Profile',
                    onClick: () => message.info('Profile page coming soon')
                  },
                  {
                    key: 'settings',
                    icon: <SettingOutlined />,
                    label: 'Settings',
                    onClick: () => setActiveKey('settings')
                  },
                  {
                    type: 'divider'
                  },
                  {
                    key: 'logout',
                    icon: <LogoutOutlined />,
                    label: 'Logout',
                    onClick: handleLogout
                  }
                ]
              }}
              placement="bottomRight"
            >
              <div style={{
                display: 'flex',
                alignItems: 'center',
                cursor: 'pointer',
                padding: '4px 12px',
                borderRadius: 8,
                transition: 'background 0.3s',
                maxWidth: '200px',
                '&:hover': {
                  background: '#f0f0f0'
                }
              }}>
                <Avatar
                  style={{
                    backgroundColor: '#1890ff',
                    marginRight: 8,
                    flexShrink: 0
                  }}
                  icon={<UserOutlined />}
                />
                <div style={{ minWidth: 0, flex: 1 }}>
                  <Text strong style={{
                    display: 'block',
                    whiteSpace: 'nowrap',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    fontSize: '14px'
                  }}>
                    {currentUser?.firstName} {currentUser?.lastName}
                  </Text>
                  <Text type="secondary" style={{
                    fontSize: 12,
                    display: 'block',
                    whiteSpace: 'nowrap',
                    overflow: 'hidden',
                    textOverflow: 'ellipsis'
                  }}>
                    {currentUser?.role?.toUpperCase()}
                  </Text>
                </div>
              </div>
            </Dropdown>
          </div>
        </Header>

        {/* Content */}
        <Content style={{ 
          margin: '24px',
          minHeight: 280,
          background: '#f0f2f5'
        }}>
          {renderContent()}
        </Content>

        {/* Footer */}
        <Layout.Footer style={{ 
          textAlign: 'center',
          background: '#fff',
          borderTop: '1px solid #f0f0f0'
        }}>
          <Text type="secondary">
            Forum Academy Admin Dashboard ©{new Date().getFullYear()} | 
            <span style={{ marginLeft: 8 }}>
              Made with <HeartOutlined style={{ color: '#ff4d4f' }} /> by Forum Academy Team
            </span>
          </Text>
        </Layout.Footer>
      </Layout>

      {/* Modals */}
      
      {/* Application Details Modal */}
      <Modal
        title="Application Details"
        visible={applicationModalVisible}
        onCancel={() => setApplicationModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setApplicationModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="reply"
            icon={<MessageOutlined />}
            onClick={() => {
              setReplyType('application');
              setReplyTarget(selectedApplication);
              setApplicationModalVisible(false);
              setReplyModalVisible(true);
            }}
          >
            Reply to Applicant
          </Button>,
          selectedApplication?.status === 'pending' && (
            <>
              <Button
                key="reject"
                danger
                onClick={() => updateApplicationStatus(selectedApplication._id, 'rejected')}
              >
                Reject
              </Button>
              <Button
                key="approve"
                type="primary"
                onClick={() => updateApplicationStatus(selectedApplication._id, 'approved')}
              >
                Approve
              </Button>
            </>
          )
        ]}
      >
        {selectedApplication && (
          <Descriptions bordered column={2}>
            <Descriptions.Item label="Full Name" span={2}>
              {selectedApplication.fullName}
            </Descriptions.Item>
            <Descriptions.Item label="Email">
              {selectedApplication.email}
            </Descriptions.Item>
            <Descriptions.Item label="Phone">
              {selectedApplication.phone}
            </Descriptions.Item>
            <Descriptions.Item label="Program">
              {selectedApplication.course || selectedApplication.program}
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              <Tag color={
                selectedApplication.status === 'pending' ? 'orange' :
                selectedApplication.status === 'approved' ? 'green' : 'red'
              }>
                {selectedApplication.status?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Applied Date">
              {moment(selectedApplication.createdAt).format('MMMM DD, YYYY')}
            </Descriptions.Item>
            <Descriptions.Item label="Message" span={2}>
              <Paragraph ellipsis={{ rows: 3, expandable: true }}>
                {selectedApplication.message}
              </Paragraph>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>

      {/* Course View Modal */}
      <Modal
        title="Course Details"
        visible={courseViewModalVisible}
        onCancel={() => setCourseViewModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setCourseViewModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="edit"
            icon={<EditOutlined />}
            onClick={() => {
              setEditingCourse(selectedCourse);
              const formValues = {
                ...selectedCourse,
                capacity: selectedCourse.maxStudents || selectedCourse.capacity || 30,
                status: selectedCourse.isActive ? 'active' : 'inactive'
              };
              
              if (selectedCourse.startDate) {
                const startDate = moment(selectedCourse.startDate);
                if (startDate.isValid()) {
                  formValues.startDate = startDate;
                }
              }
              
              if (selectedCourse.endDate) {
                const endDate = moment(selectedCourse.endDate);
                if (endDate.isValid()) {
                  formValues.endDate = endDate;
                }
              }
              
              courseForm.setFieldsValue(formValues);
              setCourseViewModalVisible(false);
              setCourseModalVisible(true);
            }}
          >
            Edit Course
          </Button>
        ]}
      >
        {selectedCourse && (
          <Descriptions bordered column={2}>
            <Descriptions.Item label="Title" span={2}>
              <Text strong>{selectedCourse.title}</Text>
            </Descriptions.Item>
            <Descriptions.Item label="Code">
              <Tag color="blue">{selectedCourse.code}</Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Category">
              <Tag color="green">{selectedCourse.category}</Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Level">
              <Tag color={
                selectedCourse.level === 'beginner' ? 'green' :
                selectedCourse.level === 'intermediate' ? 'orange' : 'red'
              }>
                {selectedCourse.level?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Description" span={2}>
              <Paragraph ellipsis={{ rows: 3, expandable: true }}>
                {selectedCourse.description}
              </Paragraph>
            </Descriptions.Item>
            <Descriptions.Item label="Duration">
              {selectedCourse.duration || 12} weeks
            </Descriptions.Item>
            <Descriptions.Item label="Capacity">
              {selectedCourse.maxStudents || selectedCourse.capacity || 30} students
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              <Tag color={selectedCourse.isActive ? 'green' : 'default'}>
                {selectedCourse.isActive ? 'Active' : 'Inactive'}
              </Tag>
            </Descriptions.Item>
            {selectedCourse.startDate && (
              <Descriptions.Item label="Start Date">
                {moment(selectedCourse.startDate).format('MMMM DD, YYYY')}
              </Descriptions.Item>
            )}
            {selectedCourse.endDate && (
              <Descriptions.Item label="End Date">
                {moment(selectedCourse.endDate).format('MMMM DD, YYYY')}
              </Descriptions.Item>
            )}
            <Descriptions.Item label="Students Enrolled" span={2}>
              <List
                dataSource={selectedCourse.students || []}
                renderItem={(studentId) => {
                  const student = students.find(s => s._id === studentId);
                  return (
                    <List.Item>
                      <Space>
                        <Avatar icon={<UserOutlined />} size="small" />
                        <Text>{student ? `${student.firstName} ${student.lastName}` : 'Unknown'}</Text>
                      </Space>
                    </List.Item>
                  );
                }}
                size="small"
                bordered={false}
                style={{ maxHeight: 200, overflow: 'auto' }}
              />
              {(!selectedCourse.students || selectedCourse.students.length === 0) && (
                <Text type="secondary">No students enrolled yet</Text>
              )}
            </Descriptions.Item>
            <Descriptions.Item label="Created" span={2}>
              {moment(selectedCourse.createdAt).format('MMMM DD, YYYY')}
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>

      {/* Message Details Modal */}
      <Modal
        title="Message Details"
        visible={messageModalVisible}
        onCancel={() => setMessageModalVisible(false)}
        width={700}
        footer={[
          <Button key="close" onClick={() => setMessageModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="reply"
            type="primary"
            icon={<MailOutlined />}
            onClick={() => {
              setReplyType('message');
              setReplyTarget(selectedMessage);
              setReplyModalVisible(true);
            }}
          >
            Reply
          </Button>
        ]}
      >
        {selectedMessage && (
          <Descriptions bordered column={1}>
            <Descriptions.Item label="From">
              {selectedMessage.name} ({selectedMessage.email})
            </Descriptions.Item>
            <Descriptions.Item label="Phone">
              {selectedMessage.phone || 'Not provided'}
            </Descriptions.Item>
            <Descriptions.Item label="Subject">
              {selectedMessage.subject}
            </Descriptions.Item>
            <Descriptions.Item label="Message">
              <Paragraph>{selectedMessage.message}</Paragraph>
            </Descriptions.Item>
            <Descriptions.Item label="Received">
              {moment(selectedMessage.createdAt).format('MMMM DD, YYYY HH:mm')}
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              <Tag color={selectedMessage.status === 'pending' ? 'orange' : 'green'}>
                {selectedMessage.status?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>

      {/* User Details Modal */}
      <Modal
        title="User Details"
        visible={userModalVisible}
        onCancel={() => setUserModalVisible(false)}
        width={700}
        footer={[
          <Button key="close" onClick={() => setUserModalVisible(false)}>
            Close
          </Button>,
          selectedUser?.isApproved !== true && (
            <Button
              key="approve"
              type="primary"
              onClick={() => updateUserStatus(selectedUser._id, true)}
            >
              Approve User
            </Button>
          ),
          selectedUser?.isApproved !== false && (
            <Button
              key="reject"
              danger
              onClick={() => updateUserStatus(selectedUser._id, false)}
            >
              Reject User
            </Button>
          )
        ]}
      >
        {selectedUser && (
          <Descriptions bordered column={2}>
            <Descriptions.Item label="Name" span={2}>
              {selectedUser.firstName} {selectedUser.lastName}
            </Descriptions.Item>
            <Descriptions.Item label="Email">
              {selectedUser.email}
            </Descriptions.Item>
            <Descriptions.Item label="Role">
              <Tag color={selectedUser.role === 'teacher' ? 'blue' : 'green'}>
                {selectedUser.role?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              {selectedUser.isApproved === true ? (
                <Tag color="green" icon={<CheckCircleOutlined />}>Approved</Tag>
              ) : selectedUser.isApproved === false ? (
                <Tag color="red" icon={<CloseCircleOutlined />}>Rejected</Tag>
              ) : (
                <Tag color="orange">Pending</Tag>
              )}
            </Descriptions.Item>
            <Descriptions.Item label="Registered">
              {moment(selectedUser.createdAt).format('MMMM DD, YYYY')}
            </Descriptions.Item>
            {selectedUser.phone && (
              <Descriptions.Item label="Phone" span={2}>
                {selectedUser.phone}
              </Descriptions.Item>
            )}
            {selectedUser.bio && (
              <Descriptions.Item label="Bio" span={2}>
                {selectedUser.bio}
              </Descriptions.Item>
            )}
          </Descriptions>
        )}
      </Modal>

      {/* Create User Modal */}
      <Modal
        title="Create New User"
        visible={createUserModalVisible}
        onCancel={() => {
          setCreateUserModalVisible(false);
          createUserForm.resetFields();
        }}
        onOk={() => createUserForm.submit()}
        width={600}
      >
        <Form
          form={createUserForm}
          layout="vertical"
          onFinish={createUser}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="firstName"
                label="First Name"
                rules={[{ required: true, message: 'Please enter first name' }]}
              >
                <Input placeholder="Enter first name" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="lastName"
                label="Last Name"
                rules={[{ required: true, message: 'Please enter last name' }]}
              >
                <Input placeholder="Enter last name" />
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="email"
            label="Email"
            rules={[
              { required: true, message: 'Please enter email' },
              { type: 'email', message: 'Please enter a valid email' }
            ]}
          >
            <Input placeholder="Enter email address" />
          </Form.Item>
          
          <Form.Item
            name="password"
            label="Password"
            rules={[
              { required: true, message: 'Please enter password' },
              { min: 6, message: 'Password must be at least 6 characters' }
            ]}
          >
            <Input.Password placeholder="Enter password" />
          </Form.Item>
          
          <Form.Item
            name="role"
            label="Role"
            rules={[{ required: true, message: 'Please select a role' }]}
          >
            <Select placeholder="Select user role">
              <Option value="student">Student</Option>
              <Option value="teacher">Teacher</Option>
              <Option value="admin">Admin</Option>
            </Select>
          </Form.Item>
          
          <Form.Item
            name="phone"
            label="Phone Number"
          >
            <Input placeholder="Enter phone number (optional)" />
          </Form.Item>
          
          <Form.Item
            name="isApproved"
            label="Approval Status"
            valuePropName="checked"
          >
            <Switch checkedChildren="Approved" unCheckedChildren="Pending" />
          </Form.Item>
        </Form>
      </Modal>

      {/* Reply Modal */}
      <Modal
        title={`Reply to ${replyTarget?.name || replyTarget?.fullName || 'User'}`}
        visible={replyModalVisible}
        onCancel={() => {
          setReplyModalVisible(false);
          replyForm.resetFields();
          setReplyType('');
          setReplyTarget(null);
        }}
        onOk={() => replyForm.submit()}
        width={600}
      >
        <Form
          form={replyForm}
          layout="vertical"
          onFinish={async (values) => {
            try {
              console.log('🔧 Attempting to send reply...', {
                replyType,
                target: replyTarget?.email,
                subject: values.subject
              });

              // Prepare email data based on reply type
              const emailData = {
                to: replyTarget?.email,
                subject: values.subject,
                message: values.message,
                type: replyType,
                relatedId: replyTarget?._id
              };

              console.log('📧 Email data prepared:', emailData);

              // Send email via API
              const response = await fetch(`${API_BASE_URL}/api/send-email`, {
                method: 'POST',
                headers: getAuthHeaders(),
                body: JSON.stringify(emailData)
              });

              console.log('📡 API Response Status:', response.status);

              if (response.ok) {
                const responseData = await response.json();
                console.log('✅ API Response Data:', responseData);
                
                if (responseData.success) {
                  if (responseData.details?.simulated || responseData.details?.queued) {
                    message.success(
                      responseData.details.simulated 
                        ? 'Reply recorded successfully! (Email service not configured - simulated)' 
                        : 'Reply queued successfully! (Will be sent when email service is available)'
                    );
                  } else {
                    message.success('Reply sent successfully!');
                  }
                  
                  // Update status if it's an application reply
                  if (replyType === 'application' && replyTarget?.status === 'pending') {
                    await updateApplicationStatus(replyTarget._id, 'contacted');
                  }
                  
                  // Update status if it's a message reply
                  if (replyType === 'message' && replyTarget?.status === 'pending') {
                    await updateContactStatus(replyTarget._id, 'resolved');
                  }
                  
                  setReplyModalVisible(false);
                  replyForm.resetFields();
                  setReplyType('');
                  setReplyTarget(null);
                  
                  // Refresh data
                  if (replyType === 'application') {
                    fetchApplications();
                  } else if (replyType === 'message') {
                    fetchContactMessages();
                  }
                } else {
                  throw new Error(responseData.message || 'Failed to send reply');
                }
              } else {
                const errorData = await response.json().catch(() => ({ message: 'Unknown error' }));
                console.error('❌ API Error Response:', errorData);
                throw new Error(errorData.message || `Server responded with ${response.status}`);
              }
            } catch (error) {
              console.error('❌ Error sending reply:', error);
              
              // Provide more specific error messages
              if (error.message.includes('fetch')) {
                message.error('Connection error. Please check if the server is running and try again.');
              } else if (error.message.includes('401')) {
                message.error('Authentication error. Please log in again.');
              } else if (error.message.includes('403')) {
                message.error('Permission denied. You may not have the required permissions.');
              } else {
                message.error(`Failed to send reply: ${error.message}`);
              }
            }
          }}
        >
          {/* Display recipient information */}
          <div style={{ 
            background: '#f0f2f5', 
            padding: '12px', 
            borderRadius: '8px',
            marginBottom: '16px' 
          }}>
            <Text strong>Replying to: </Text>
            <Text>{replyTarget?.email}</Text>
            {replyType === 'application' && (
              <>
                <br />
                <Text type="secondary">
                  Application for: {replyTarget?.course || replyTarget?.program || 'General Application'}
                </Text>
              </>
            )}
            {replyType === 'message' && replyTarget?.subject && (
              <>
                <br />
                <Text type="secondary">
                  Original Subject: {replyTarget.subject}
                </Text>
              </>
            )}
          </div>

          <Form.Item
            name="subject"
            label="Subject"
            rules={[{ required: true, message: 'Please enter subject' }]}
            initialValue={
              replyType === 'application' 
                ? `Re: Your Application to Forum Academy`
                : replyTarget?.subject 
                  ? `Re: ${replyTarget.subject}` 
                  : ''
            }
          >
            <Input placeholder="Enter email subject" />
          </Form.Item>
          
          <Form.Item
            name="message"
            label="Message"
            rules={[{ required: true, message: 'Please enter your message' }]}
          >
            <TextArea 
              rows={8} 
              placeholder={
                replyType === 'application'
                  ? "Dear Applicant,\n\nThank you for your application to Forum Academy...\n\nBest regards,\nForum Academy Team"
                  : "Type your reply message here..."
              }
            />
          </Form.Item>

          {/* Quick Templates */}
          <Form.Item label="Quick Templates">
            <Space wrap>
              {replyType === 'application' && (
                <>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.fullName || 'Applicant'},\n\nThank you for your application to Forum Academy. We have received your application and are currently reviewing it.\n\nWe will contact you within 3-5 business days with an update on your application status.\n\nIf you have any questions in the meantime, please don't hesitate to reach out.\n\nBest regards,\nForum Academy Admissions Team`
                      });
                    }}
                  >
                    Application Received
                  </Button>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.fullName || 'Applicant'},\n\nWe need additional information to process your application. Please provide:\n\n1. [Required Document/Information]\n2. [Required Document/Information]\n\nPlease reply to this email with the requested information.\n\nBest regards,\nForum Academy Admissions Team`
                      });
                    }}
                  >
                    Request Information
                  </Button>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.fullName || 'Applicant'},\n\nCongratulations! We are pleased to inform you that your application to Forum Academy has been approved.\n\nNext steps:\n1. Complete your enrollment by [date]\n2. Submit required documents\n3. Attend orientation on [date]\n\nWelcome to Forum Academy!\n\nBest regards,\nForum Academy Admissions Team`
                      });
                    }}
                  >
                    Acceptance Letter
                  </Button>
                </>
              )}
              {replyType === 'message' && (
                <>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.name || 'User'},\n\nThank you for contacting Forum Academy. We have received your message and will respond within 24-48 hours.\n\nBest regards,\nForum Academy Support Team`
                      });
                    }}
                  >
                    Acknowledgment
                  </Button>
                  <Button
                    size="small"
                    onClick={() => {
                      replyForm.setFieldsValue({
                        message: `Dear ${replyTarget?.name || 'User'},\n\nThank you for your inquiry. [Your detailed response here]\n\nIf you have any further questions, please don't hesitate to contact us.\n\nBest regards,\nForum Academy Support Team`
                      });
                    }}
                  >
                    General Response
                  </Button>
                </>
              )}
            </Space>
          </Form.Item>
          
          <Form.Item
            name="attachments"
            label="Attachments (Optional)"
          >
            <Upload beforeUpload={() => false}>
              <Button icon={<UploadOutlined />}>Attach Files</Button>
            </Upload>
          </Form.Item>

          <Form.Item
            name="sendCopy"
            valuePropName="checked"
          >
            <Checkbox>Send me a copy of this email</Checkbox>
          </Form.Item>
        </Form>
      </Modal>

      {/* Course Modal */}
      <Modal
        title={editingCourse ? 'Edit Course' : 'Create New Course'}
        visible={courseModalVisible}
        onCancel={() => {
          setCourseModalVisible(false);
          courseForm.resetFields();
          setEditingCourse(null);
        }}
        onOk={() => courseForm.submit()}
        width={800}
      >
        <Form
          form={courseForm}
          layout="vertical"
          onFinish={handleCreateCourse}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="title"
                label="Course Title"
                rules={[{ required: true, message: 'Please enter course title' }]}
              >
                <Input placeholder="Enter course title" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="code"
                label="Course Code"
                rules={[{ required: true, message: 'Please enter course code' }]}
              >
                <Input placeholder="e.g., CS101" />
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="description"
            label="Description"
            rules={[{ required: true, message: 'Please enter course description' }]}
          >
            <TextArea rows={4} placeholder="Enter course description" />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="category"
                label="Category"
                rules={[{ required: true, message: 'Please select category' }]}
              >
                <Select placeholder="Select category">
                  <Option value="language">Language</Option>
                  <Option value="business">Business</Option>
                  <Option value="technology">Technology</Option>
                  <Option value="arts">Arts</Option>
                  <Option value="science">Science</Option>
                  <Option value="other">Other</Option>
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="level"
                label="Level"
                rules={[{ required: true, message: 'Please select level' }]}
              >
                <Select placeholder="Select level">
                  <Option value="beginner">Beginner</Option>
                  <Option value="intermediate">Intermediate</Option>
                  <Option value="advanced">Advanced</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="startDate"
                label="Start Date"
                rules={[{ required: true, message: 'Please select start date' }]}
              >
                <DatePicker style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="endDate"
                label="End Date"
                rules={[{ required: true, message: 'Please select end date' }]}
              >
                <DatePicker style={{ width: '100%' }} />
              </Form.Item>
            </Col>
          </Row>
          
          <Row gutter={16}>
            <Col span={8}>
              <Form.Item
                name="duration"
                label="Duration (weeks)"
                rules={[{ required: true, message: 'Please enter duration' }]}
                initialValue={12}
              >
                <InputNumber min={1} max={52} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="capacity"
                label="Maximum Students"
                rules={[{ required: true, message: 'Please enter capacity' }]}
                initialValue={30}
              >
                <InputNumber min={1} max={500} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={8}>
              <Form.Item
                name="status"
                label="Status"
                initialValue="active"
              >
                <Select>
                  <Option value="active">Active</Option>
                  <Option value="inactive">Inactive</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Modal>

      {/* Material Upload Modal */}
      <Modal
        title="Upload Course Material"
        visible={materialModalVisible}
        onCancel={() => {
          setMaterialModalVisible(false);
          materialForm.resetFields();
          setFileList([]);
        }}
        onOk={() => materialForm.submit()}
        width={700}
      >
        <Form
          form={materialForm}
          layout="vertical"
          onFinish={handleUploadMaterial}
        >
          <Form.Item
            name="title"
            label="Material Title"
            rules={[{ required: true, message: 'Please enter material title' }]}
          >
            <Input placeholder="Enter material title" />
          </Form.Item>
          
          <Form.Item
            name="description"
            label="Description"
          >
            <TextArea rows={3} placeholder="Enter material description (optional)" />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="course"
                label="Course"
                rules={[{ required: true, message: 'Please select course' }]}
              >
                <Select placeholder="Select course">
                  {courses.map(course => (
                    <Option key={course._id} value={course._id}>
                      {course.title}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="category"
                label="Category"
                rules={[{ required: true, message: 'Please select category' }]}
              >
                <Select placeholder="Select category">
                  <Option value="lecture">Lecture</Option>
                  <Option value="assignment">Assignment</Option>
                  <Option value="resource">Resource</Option>
                  <Option value="video">Video</Option>
                  <Option value="document">Document</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            label="Upload File"
            rules={[{ required: true, message: 'Please upload a file' }]}
          >
            <Dragger
              fileList={fileList}
              beforeUpload={(file) => {
                setFileList([file]);
                return false;
              }}
              onRemove={() => setFileList([])}
              maxCount={1}
            >
              <p className="ant-upload-drag-icon">
                <InboxOutlined />
              </p>
              <p className="ant-upload-text">Click or drag file to this area to upload</p>
              <p className="ant-upload-hint">
                Support for PDF, DOC, DOCX, PPT, PPTX, XLS, XLSX, ZIP, RAR
              </p>
            </Dragger>
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="week"
                label="Week Number"
              >
                <InputNumber min={1} max={52} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="accessLevel"
                label="Access Level"
              >
                <Select defaultValue="course_students">
                  <Option value="public">Public</Option>
                  <Option value="course_students">Course Students Only</Option>
                  <Option value="premium">Premium Members</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
        </Form>
