          quizForm.resetFields();
          setEditingQuiz(null);
          setQuestions([]);
        }}
        footer={null}
        width={900}
      >
        <Form
          form={quizForm}
          layout="vertical"
          onFinish={handleCreateQuiz}
        >
          <Tabs defaultActiveKey="basic">
            <TabPane tab="Basic Information" key="basic">
              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="title"
                    label="Quiz Title"
                    rules={[{ required: true, message: 'Please enter quiz title' }]}
                  >
                    <Input placeholder="Enter quiz title" />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="course"
                    label="Course"
                    rules={[{ required: true, message: 'Please select course' }]}
                  >
                    <Select placeholder="Select course">
                      {courses.map(course => (
                        <Option key={course._id} value={course._id}>
                          {course.title}
                        </Option>
                      ))}
                    </Select>
                  </Form.Item>
                </Col>
              </Row>
              
              <Form.Item
                name="description"
                label="Description"
              >
                <TextArea rows={3} placeholder="Enter quiz description" />
              </Form.Item>
              
              <Row gutter={16}>
                <Col span={8}>
                  <Form.Item
                    name="duration"
                    label="Duration (minutes)"
                    rules={[{ required: true, message: 'Please enter duration' }]}
                  >
                    <InputNumber min={1} max={300} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="passingScore"
                    label="Passing Score (%)"
                    rules={[{ required: true, message: 'Please enter passing score' }]}
                  >
                    <InputNumber min={0} max={100} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="attempts"
                    label="Max Attempts"
                  >
                    <InputNumber min={1} max={10} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
              </Row>
              
              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="availableFrom"
                    label="Available From"
                  >
                    <DatePicker showTime style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="availableTo"
                    label="Available Until"
                  >
                    <DatePicker showTime style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
              </Row>
            </TabPane>
            
            <TabPane tab={`Questions (${questions.length})`} key="questions">
              <Button
                type="dashed"
                icon={<PlusOutlined />}
                onClick={() => setQuestionsModalVisible(true)}
                style={{ width: '100%', marginBottom: 16 }}
              >
                Add Question
              </Button>
              
              {questions.length > 0 ? (
                <List
                  dataSource={questions}
                  renderItem={(question, index) => (
                    <List.Item
                      actions={[
                        <Button
                          icon={<EditOutlined />}
                          size="small"
                          onClick={() => message.info('Edit functionality coming soon')}
                        />,
                        <Button
                          icon={<DeleteOutlined />}
                          size="small"
                          danger
                          onClick={() => removeQuestion(question.id)}
                        />
                      ]}
                    >
                      <List.Item.Meta
                        avatar={<Avatar>{index + 1}</Avatar>}
                        title={question.question}
                        description={
                          <div>
                            <Tag color="blue">{question.type}</Tag>
                            <Tag color="green">Points: {question.points || 1}</Tag>
                            {question.type === 'multiple_choice' && (
                              <div style={{ marginTop: 8 }}>
                                Options: {question.options?.join(', ')}
                              </div>
                            )}
                          </div>
                        }
                      />
                    </List.Item>
                  )}
                />
              ) : (
                <Empty description="No questions added yet" />
              )}
            </TabPane>
          </Tabs>
          
          <div style={{ marginTop: 24, textAlign: 'right' }}>
            <Space>
              <Button onClick={() => {
                setQuizModalVisible(false);
                quizForm.resetFields();
                setQuestions([]);
              }}>
                Cancel
              </Button>
              <Button type="primary" htmlType="submit">
                {editingQuiz ? 'Update Quiz' : 'Create Quiz'}
              </Button>
            </Space>
          </div>
        </Form>
      </Modal>

      {/* Add Question Modal */}
      <Modal
        title="Add Question"
        visible={questionsModalVisible}
        onCancel={() => {
          setQuestionsModalVisible(false);
          questionForm.resetFields();
        }}
        onOk={() => {
          addQuestion();
          setQuestionsModalVisible(false);
        }}
        width={600}
      >
        <Form
          form={questionForm}
          layout="vertical"
        >
          <Form.Item
            name="question"
            label="Question"
            rules={[{ required: true, message: 'Please enter question' }]}
          >
            <TextArea rows={3} placeholder="Enter your question" />
          </Form.Item>
          
          <Form.Item
            name="type"
            label="Question Type"
            rules={[{ required: true, message: 'Please select question type' }]}
          >
            <Select placeholder="Select question type">
              <Option value="multiple_choice">Multiple Choice</Option>
              <Option value="true_false">True/False</Option>
              <Option value="short_answer">Short Answer</Option>
              <Option value="essay">Essay</Option>
            </Select>
          </Form.Item>
          
          <Form.Item
            noStyle
            shouldUpdate={(prevValues, currentValues) => 
              prevValues.type !== currentValues.type
            }
          >
            {({ getFieldValue }) =>
              getFieldValue('type') === 'multiple_choice' ? (
                <Form.Item
                  name="options"
                  label="Options"
                  rules={[{ required: true, message: 'Please add options' }]}
                >
                  <Select
                    mode="tags"
                    placeholder="Add options (press Enter after each)"
                    style={{ width: '100%' }}
                  />
                </Form.Item>
              ) : null
            }
          </Form.Item>
          
          <Form.Item
            name="correctAnswer"
            label="Correct Answer"
            rules={[{ required: true, message: 'Please enter correct answer' }]}
          >
            <Input placeholder="Enter the correct answer" />
          </Form.Item>
          
          <Form.Item
            name="points"
            label="Points"
          >
            <InputNumber min={1} max={100} defaultValue={1} />
          </Form.Item>
        </Form>
      </Modal>

      {/* Homework Modal */}
      <Modal
        title={editingHomework ? 'Edit Homework' : 'Create New Homework'}
        visible={homeworkModalVisible}
        onCancel={() => {
          setHomeworkModalVisible(false);
          homeworkForm.resetFields();
          setEditingHomework(null);
        }}
        onOk={() => homeworkForm.submit()}
        width={800}
      >
        <Form
          form={homeworkForm}
          layout="vertical"
          onFinish={handleCreateHomework}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="title"
                label="Assignment Title"
                rules={[{ required: true, message: 'Please enter assignment title' }]}
              >
                <Input placeholder="Enter assignment title" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="course"
                label="Course"
                rules={[{ required: true, message: 'Please select course' }]}
              >
                <Select placeholder="Select course">
                  {courses.map(course => (
                    <Option key={course._id} value={course._id}>
                      {course.title}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="description"
            label="Description"
            rules={[{ required: true, message: 'Please enter assignment description' }]}
          >
            <TextArea rows={4} placeholder="Enter assignment description" />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="dueDate"
                label="Due Date"
                rules={[{ required: true, message: 'Please select due date' }]}
              >
                <DatePicker showTime style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="totalPoints"
                label="Total Points"
                rules={[{ required: true, message: 'Please enter total points' }]}
              >
                <InputNumber min={1} max={1000} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="instructions"
            label="Instructions"
          >
            <TextArea rows={3} placeholder="Enter detailed instructions for students" />
          </Form.Item>
        </Form>
      </Modal>

      {/* Exercise Modal */}
      <Modal
        title={editingExercise ? 'Edit Exercise' : 'Create New Listening Exercise'}
        visible={exerciseModalVisible}
        onCancel={() => {
          setExerciseModalVisible(false);
          exerciseForm.resetFields();
          setEditingExercise(null);
          setAudioFile(null);
          setFileList([]);
          setQuestions([]);
        }}
        footer={null}
        width={900}
      >
        <Form
          form={exerciseForm}
          layout="vertical"
          onFinish={handleCreateExercise}
        >
          <Tabs defaultActiveKey="basic">
            <TabPane tab="Basic Information" key="basic">
              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="title"
                    label="Exercise Title"
                    rules={[{ required: true, message: 'Please enter exercise title' }]}
                  >
                    <Input placeholder="Enter exercise title" />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="course"
                    label="Course"
                    rules={[{ required: true, message: 'Please select course' }]}
                  >
                    <Select placeholder="Select course">
                      {courses.map(course => (
                        <Option key={course._id} value={course._id}>
                          {course.title}
                        </Option>
                      ))}
                    </Select>
                  </Form.Item>
                </Col>
              </Row>
              
              <Form.Item
                name="description"
                label="Description"
              >
                <TextArea rows={3} placeholder="Enter exercise description" />
              </Form.Item>
              
              <Row gutter={16}>
                <Col span={8}>
                  <Form.Item
                    name="level"
                    label="Difficulty Level"
                    rules={[{ required: true, message: 'Please select level' }]}
                  >
                    <Select placeholder="Select level">
                      <Option value="beginner">Beginner</Option>
                      <Option value="intermediate">Intermediate</Option>
                      <Option value="advanced">Advanced</Option>
                    </Select>
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="timeLimit"
                    label="Time Limit (minutes)"
                  >
                    <InputNumber min={1} max={120} defaultValue={30} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="playLimit"
                    label="Play Limit"
                  >
                    <InputNumber min={1} max={10} defaultValue={3} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
              </Row>
              
              <Form.Item
                name="instructions"
                label="Instructions"
              >
                <TextArea rows={3} placeholder="Enter instructions for students" />
              </Form.Item>
              
              <Form.Item
                label="Audio File (MP3/WAV)"
                required={!editingExercise}
              >
                <Upload
                  beforeUpload={(file) => {
                    // Validate file type
                    const allowedTypes = ['audio/mp3', 'audio/mpeg', 'audio/wav', 'audio/x-wav'];
                    const isValidType = allowedTypes.includes(file.type) || 
                                       file.name.toLowerCase().endsWith('.mp3') || 
                                       file.name.toLowerCase().endsWith('.wav');
                    
                    if (!isValidType) {
                      message.error('Please upload a valid MP3 or WAV audio file');
                      return Upload.LIST_IGNORE;
                    }
                    
                    // Check file size (50MB limit)
                    const isLessThan50M = file.size / 1024 / 1024 < 50;
                    if (!isLessThan50M) {
                      message.error('Audio file must be smaller than 50MB!');
                      return Upload.LIST_IGNORE;
                    }
                    
                    setAudioFile(file);
                    setFileList([file]);
                    
                    // Create a preview URL for the uploaded file
                    const url = URL.createObjectURL(file);
                    console.log('Audio file selected:', file.name, 'Type:', file.type, 'Size:', (file.size / 1024 / 1024).toFixed(2) + 'MB');
                    
                    return false; // Prevent automatic upload
                  }}
                  onRemove={() => {
                    setAudioFile(null);
                    setFileList([]);
                  }}
                  fileList={fileList}
                  accept=".mp3,.wav,audio/mp3,audio/mpeg,audio/wav"
                  maxCount={1}
                  showUploadList={{
                    showPreviewIcon: true,
                    showRemoveIcon: true,
                    showDownloadIcon: false,
                  }}
                >
                  <Button icon={<UploadOutlined />} disabled={fileList.length >= 1}>
                    {fileList.length >= 1 ? 'Audio File Selected' : 'Select MP3/WAV File'}
                  </Button>
                </Upload>
                {audioFile && (
                  <div style={{ marginTop: 8 }}>
                    <Text type="secondary">
                      Selected: {audioFile.name} ({(audioFile.size / 1024 / 1024).toFixed(2)} MB)
                    </Text>
                  </div>
                )}
                {editingExercise?.audioUrl && !audioFile && (
                  <div style={{ marginTop: 8 }}>
                    <Text type="success">Current audio file: {editingExercise.originalFileName || 'audio.mp3'}</Text>
                    <br />
                    <Text type="secondary">Upload a new file to replace the current one</Text>
                  </div>
                )}
              </Form.Item>
              
              <Form.Item
                name="transcript"
                label="Transcript (Optional)"
              >
                <TextArea rows={4} placeholder="Enter audio transcript" />
              </Form.Item>
            </TabPane>
            
            <TabPane tab={`Questions (${questions.length})`} key="questions">
              <Button
                type="dashed"
                icon={<PlusOutlined />}
                onClick={() => setQuestionsModalVisible(true)}
                style={{ width: '100%', marginBottom: 16 }}
              >
                Add Question
              </Button>
              
              {questions.length > 0 ? (
                <List
                  dataSource={questions}
                  renderItem={(question, index) => (
                    <List.Item
                      actions={[
                        <Button
                          icon={<DeleteOutlined />}
                          size="small"
                          danger
                          onClick={() => removeQuestion(question.id)}
                        />
                      ]}
                    >
                      <List.Item.Meta
                        avatar={<Avatar>{index + 1}</Avatar>}
                        title={question.question}
                        description={
                          <div>
                            <Tag color="blue">{question.type}</Tag>
                            <Tag color="green">Points: {question.points || 1}</Tag>
                          </div>
                        }
                      />
                    </List.Item>
                  )}
                />
              ) : (
                <Empty description="No questions added yet" />
              )}
            </TabPane>
          </Tabs>
          
          <div style={{ marginTop: 24, textAlign: 'right' }}>
            <Space>
              <Button onClick={() => {
                setExerciseModalVisible(false);
                exerciseForm.resetFields();
                setQuestions([]);
                setAudioFile(null);
                setFileList([]);
                setEditingExercise(null);
              }}>
                Cancel
              </Button>
              <Button type="primary" htmlType="submit">
                {editingExercise ? 'Update Exercise' : 'Create Exercise'}
              </Button>
            </Space>
          </div>
        </Form>
      </Modal>

      {/* Submissions Modal */}
      <Modal
        title="View Submissions"
        visible={submissionsModalVisible}
        onCancel={() => setSubmissionsModalVisible(false)}
        width={1000}
        footer={[
          <Button key="close" onClick={() => setSubmissionsModalVisible(false)}>
            Close
          </Button>
        ]}
      >
        <Table
          columns={[
            {
              title: 'Student',
              key: 'student',
              render: (_, record) => (
                <div>
                  <Text strong>{record.studentName || 'Unknown Student'}</Text>
                  <br />
                  <Text type="secondary" style={{ fontSize: '12px' }}>
                    {record.studentEmail || 'No email'}
                  </Text>
                </div>
              )
            },
            {
              title: 'Score',
              dataIndex: 'score',
              key: 'score',
              render: (score, record) => {
                const percentage = record.totalPoints ? Math.round((score / record.totalPoints) * 100) : 0;
                return (
                  <div>
                    <Text strong>{score || 0}/{record.totalPoints || 0}</Text>
                    <br />
                    <Progress
                      percent={percentage}
                      size="small"
                      strokeColor={percentage >= 70 ? '#52c41a' : percentage >= 40 ? '#faad14' : '#f5222d'}
                    />
                  </div>
                );
              }
            },
            {
              title: 'Submitted',
              dataIndex: 'submittedAt',
              key: 'submittedAt',
              render: (date) => moment(date).format('MMM DD, YYYY HH:mm')
            },
            {
              title: 'Status',
              dataIndex: 'status',
              key: 'status',
              render: (status) => (
                <Tag color={status === 'graded' ? 'green' : 'orange'}>
                  {status?.toUpperCase() || 'PENDING'}
                </Tag>
              )
            },
            {
              title: 'Actions',
              key: 'actions',
              render: (_, record) => (
                <Space>
                  <Button
                    icon={<EyeOutlined />}
                    size="small"
                    onClick={() => {
                      setSelectedSubmission(record);
                      setViewModalVisible(true);
                    }}
                  >
                    View
                  </Button>
                  <Button
                    icon={<EditOutlined />}
                    size="small"
                    onClick={() => {
                      setSelectedSubmission(record);
                      setGradingModalVisible(true);
                    }}
                  >
                    Grade
                  </Button>
                </Space>
              )
            }
          ]}
          dataSource={submissions}
          rowKey="_id"
          pagination={{
            pageSize: 10,
            showSizeChanger: true
          }}
        />
      </Modal>

      {/* Progress Modal */}
      <Modal
        title="Student Progress Details"
        visible={progressModalVisible}
        onCancel={() => setProgressModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setProgressModalVisible(false)}>
            Close
          </Button>
        ]}
      >
        {selectedProgress && (
          <div>
            <Descriptions bordered column={2} style={{ marginBottom: 24 }}>
              <Descriptions.Item label="Student Name" span={2}>
                {selectedProgress.firstName} {selectedProgress.lastName}
              </Descriptions.Item>
              <Descriptions.Item label="Email">
                {selectedProgress.email}
              </Descriptions.Item>
              <Descriptions.Item label="Registration Date">
                {moment(selectedProgress.createdAt).format('MMMM DD, YYYY')}
              </Descriptions.Item>
            </Descriptions>
            
            <Card title="Course Progress" style={{ marginBottom: 16 }}>
              <Row gutter={[16, 16]}>
                <Col span={8}>
                  <Statistic
                    title="Courses Enrolled"
                    value={Math.floor(Math.random() * 5) + 1}
                    prefix={<BookOutlined />}
                  />
                </Col>
                <Col span={8}>
                  <Statistic
                    title="Avg. Progress"
                    value={Math.floor(Math.random() * 100)}
                    suffix="%"
                    prefix={<TrophyOutlined />}
                  />
                </Col>
                <Col span={8}>
                  <Statistic
                    title="Assignments Completed"
                    value={Math.floor(Math.random() * 20)}
                    prefix={<CheckSquareOutlined />}
                  />
                </Col>
              </Row>
            </Card>
            
            <Card title="Recent Activity">
              <Timeline>
                <Timeline.Item color="green">
                  <Text>Completed Quiz: JavaScript Basics</Text>
                  <br />
                  <Text type="secondary">2 days ago</Text>
                </Timeline.Item>
                <Timeline.Item color="blue">
                  <Text>Submitted Homework: React Components</Text>
                  <br />
                  <Text type="secondary">5 days ago</Text>
                </Timeline.Item>
                <Timeline.Item color="orange">
                  <Text>Downloaded Material: CSS Grid Guide</Text>
                  <br />
                  <Text type="secondary">1 week ago</Text>
                </Timeline.Item>
              </Timeline>
            </Card>
          </div>
        )}
      </Modal>

      {/* Preview Modal */}
      <Modal
        title="Material Preview"
        visible={previewModalVisible}
        onCancel={() => setPreviewModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setPreviewModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="download"
            type="primary"
            icon={<DownloadOutlined />}
            onClick={() => {
              if (selectedMaterial) {
                window.open(`${API_BASE_URL}/uploads/${selectedMaterial.filePath}`, '_blank');
              }
            }}
          >
            Download
          </Button>
        ]}
      >
        {selectedMaterial && (
          <div>
            <Descriptions bordered column={2} style={{ marginBottom: 24 }}>
              <Descriptions.Item label="Title" span={2}>
                {selectedMaterial.title}
              </Descriptions.Item>
              <Descriptions.Item label="Description" span={2}>
                {selectedMaterial.description || 'No description'}
              </Descriptions.Item>
              <Descriptions.Item label="Category">
                {selectedMaterial.category}
              </Descriptions.Item>
              <Descriptions.Item label="File Size">
                {((selectedMaterial.fileSize || 0) / (1024 * 1024)).toFixed(2)} MB
              </Descriptions.Item>
              <Descriptions.Item label="Uploaded">
                {moment(selectedMaterial.createdAt).format('MMMM DD, YYYY')}
              </Descriptions.Item>
              <Descriptions.Item label="Access Level">
                {selectedMaterial.accessLevel || 'course_students'}
              </Descriptions.Item>
            </Descriptions>
            
            <Card title="File Preview">
              <div style={{ textAlign: 'center', padding: '40px' }}>
                {selectedMaterial.fileType === 'pdf' ? (
                  <div>
                    <FileTextOutlined style={{ fontSize: 64, color: '#1890ff' }} />
                    <br />
                    <Text>PDF Document</Text>
                  </div>
                ) : selectedMaterial.fileType === 'video' ? (
                  <div>
                    <VideoCameraOutlined style={{ fontSize: 64, color: '#52c41a' }} />
                    <br />
                    <Text>Video File</Text>
                  </div>
                ) : (
                  <div>
                    <FileOutlined style={{ fontSize: 64, color: '#faad14' }} />
                    <br />
                    <Text>Document File</Text>
                  </div>
                )}
              </div>
            </Card>
          </div>
        )}
      </Modal>

      {/* Results Modal */}
      <Modal
        title="Quiz Results & Analytics"
        visible={resultsModalVisible}
        onCancel={() => setResultsModalVisible(false)}
        width={1000}
        footer={[
          <Button key="close" onClick={() => setResultsModalVisible(false)}>
            Close
          </Button>
        ]}
      >
        {selectedQuiz && (
          <div>
            <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="Total Submissions"
                    value={selectedQuiz.submissions?.length || 0}
                    prefix={<FormOutlined />}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="Average Score"
                    value={78}
                    suffix="%"
                    prefix={<TrophyOutlined />}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="Pass Rate"
                    value={85}
                    suffix="%"
                    prefix={<CheckCircleOutlined />}
                  />
                </Card>
              </Col>
              <Col span={6}>
                <Card>
                  <Statistic
                    title="Completion Rate"
                    value={92}
                    suffix="%"
                    prefix={<ClockCircleOutlined />}
                  />
                </Card>
              </Col>
            </Row>
            
            <Row gutter={[16, 16]}>
              <Col span={12}>
                <Card title="Score Distribution">
                  <Bar
                    data={{
                      labels: ['0-40%', '41-60%', '61-80%', '81-100%'],
                      datasets: [{
                        label: 'Number of Students',
                        data: [2, 5, 8, 12],
                        backgroundColor: [
                          '#f5222d',
                          '#faad14',
                          '#1890ff',
                          '#52c41a'
                        ]
                      }]
                    }}
                    options={{
                      responsive: true,
                      plugins: {
                        legend: {
                          display: false
                        }
                      }
                    }}
                  />
                </Card>
              </Col>
              <Col span={12}>
                <Card title="Question Analysis">
                  <List
                    dataSource={selectedQuiz.questions?.slice(0, 5) || []}
                    renderItem={(question, index) => (
                      <List.Item>
                        <List.Item.Meta
                          avatar={<Avatar>{index + 1}</Avatar>}
                          title={`Question ${index + 1}`}
                          description={
                            <div>
                              <Progress
                                percent={Math.floor(Math.random() * 100)}
                                size="small"
                                format={(percent) => `${percent}% correct`}
                              />
                            </div>
                          }
                        />
                      </List.Item>
                    )}
                  />
                </Card>
              </Col>
            </Row>
          </div>
        )}
      </Modal>

      {/* Grading Modal */}
      <Modal
        title="Grade Submission"
        visible={gradingModalVisible}
        onCancel={() => setGradingModalVisible(false)}
        onOk={() => gradingForm.submit()}
        width={700}
      >
        <Form
          form={gradingForm}
          layout="vertical"
          onFinish={(values) => {
            message.success('Grade submitted successfully!');
            setGradingModalVisible(false);
            gradingForm.resetFields();
          }}
        >
          {selectedSubmission && (
            <div>
              <Descriptions bordered column={2} style={{ marginBottom: 24 }}>
                <Descriptions.Item label="Student">
                  {selectedSubmission.studentName || 'Unknown Student'}
                </Descriptions.Item>
                <Descriptions.Item label="Assignment">
                  {selectedHomework?.title || selectedQuiz?.title || 'Unknown'}
                </Descriptions.Item>
                <Descriptions.Item label="Submitted">
                  {moment(selectedSubmission.submittedAt).format('MMMM DD, YYYY HH:mm')}
                </Descriptions.Item>
                <Descriptions.Item label="Current Score">
                  {selectedSubmission.score || 0}/{selectedSubmission.totalPoints || 0}
                </Descriptions.Item>
              </Descriptions>
              
              <Form.Item
                name="score"
                label="Score"
                rules={[{ required: true, message: 'Please enter score' }]}
              >
                <InputNumber
                  min={0}
                  max={selectedSubmission.totalPoints || 100}
                  style={{ width: '100%' }}
                  placeholder="Enter score"
                />
              </Form.Item>
              
              <Form.Item
                name="feedback"
                label="Feedback"
              >
                <TextArea
                  rows={4}
                  placeholder="Enter feedback for the student"
                />
              </Form.Item>
              
              <Form.Item
                name="status"
                label="Status"
              >
                <Select defaultValue="graded">
                  <Option value="graded">Graded</Option>
                  <Option value="needs_revision">Needs Revision</Option>
                  <Option value="excellent">Excellent</Option>
                </Select>
              </Form.Item>
            </div>
          )}
        </Form>
      </Modal>

      {/* View Submission Modal */}
      <Modal
        title="Submission Details"
        visible={viewModalVisible}
        onCancel={() => setViewModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setViewModalVisible(false)}>
            Close
          </Button>
        ]}
      >
        {selectedSubmission && (
          <div>
            <Descriptions bordered column={2}>
              <Descriptions.Item label="Student" span={2}>
                {selectedSubmission.studentName || 'Unknown Student'}
              </Descriptions.Item>
              <Descriptions.Item label="Assignment">
                {selectedHomework?.title || selectedQuiz?.title || 'Unknown'}
              </Descriptions.Item>
              <Descriptions.Item label="Score">
                {selectedSubmission.score || 0}/{selectedSubmission.totalPoints || 0}
              </Descriptions.Item>
              <Descriptions.Item label="Submitted">
                {moment(selectedSubmission.submittedAt).format('MMMM DD, YYYY HH:mm')}
              </Descriptions.Item>
              <Descriptions.Item label="Status">
                <Tag color={selectedSubmission.status === 'graded' ? 'green' : 'orange'}>
                  {selectedSubmission.status?.toUpperCase() || 'PENDING'}
                </Tag>
              </Descriptions.Item>
              <Descriptions.Item label="Feedback" span={2}>
                {selectedSubmission.feedback || 'No feedback provided'}
              </Descriptions.Item>
            </Descriptions>
            
            {selectedSubmission.answers && (
              <Card title="Student Answers" style={{ marginTop: 16 }}>
                <List
                  dataSource={selectedSubmission.answers}
                  renderItem={(answer, index) => (
                    <List.Item>
                      <List.Item.Meta
                        avatar={<Avatar>{index + 1}</Avatar>}
                        title={`Question ${index + 1}`}
                        description={
                          <div>
                            <Text strong>Answer: </Text>
                            <Text>{answer.answer || 'No answer provided'}</Text>
                            <br />
                            <Text strong>Correct: </Text>
                            <Tag color={answer.isCorrect ? 'green' : 'red'}>
                              {answer.isCorrect ? 'Yes' : 'No'}
                            </Tag>
                          </div>
                        }
                      />
                    </List.Item>
                  )}
                />
              </Card>
            )}
          </div>
        )}
      </Modal>
    </Layout>
  );
};

export default AdminFacultyDashboard;
